import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const navigate = useNavigate();

  // ✅ Protect route (only logged-in users)
  useEffect(() => {
    const user = localStorage.getItem("user");

    if (!user) {
      navigate("/login");
    }
  }, [navigate]);

  // ✅ Fetch questions
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data))
      .catch((err) => console.error(err));
  }, []);

  // ✅ Logout function
  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };
const [notes, setNotes] = useState([]);

useEffect(() => {
  fetch("http://localhost:5000/api/notes")
    .then((res) => res.json())
    .then((data) => setNotes(data));
}, []);
  // ✅ Get user info
  const user = JSON.parse(localStorage.getItem("user"));

  return (
    <div className="dashboard-full">

      {/* HEADER */}
      <div className="dashboard-header">
        <h2>Dashboard</h2>

        {/* Right side buttons */}
        <div className="top-right">
          <button onClick={() => navigate("/")}>Home</button>

          <button onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>


      {/* QUESTIONS */}
      {
        questions.length === 0 ? (
          <p style={{ textAlign: "center" }}>No questions yet</p>
        ) : (
          questions.map((q) => (
            <div key={q._id} className="dashboard-question">
              <h4>{q.title}</h4>
              <p>{q.description}</p>

              <div className="dashboard-footer">
                <span className="dashboard-tag">
                  Asked by {user?.role || "User"}
                </span>

                <Link to={`/answers/${q._id}`} className="dashboard-btn">
                  View Answer
                </Link>
              </div>
            </div>
          ))
        )
      }

      {/* ASK QUESTION BUTTON */}
      <Link to="/ask" className="dashboard-ask">
        Ask New Question
      </Link>

    </div >
  );
}

export default Dashboard;
